 namespace League\CommonMark\Block\Renderer; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Element\Paragraph; use League\CommonMark\ElementRendererInterface; use League\CommonMark\HtmlElement; final class ParagraphRenderer implements BlockRendererInterface { public function render(AbstractBlock $block, ElementRendererInterface $htmlRenderer, bool $inTightList = false) { if (!($block instanceof Paragraph)) { throw new \InvalidArgumentException('Incompatible block type: ' . \get_class($block)); } if ($inTightList) { return $htmlRenderer->renderInlines($block->children()); } $attrs = $block->getData('attributes', []); return new HtmlElement('p', $attrs, $htmlRenderer->renderInlines($block->children())); } } 